import bisect

class Solution:
    def kthSmallestProduct(self, nums1, nums2, k):
        n2 = len(nums2)

        def count_le(mid):
            total = 0
            for a in nums1:
                if a == 0:
                    if mid >= 0:
                        total += n2
                elif a > 0:
                    thr = mid // a
                    total += bisect.bisect_right(nums2, thr)
                else:
                    q = -a
                    b_min = -(mid // q)
                    total += n2 - bisect.bisect_left(nums2, b_min)
            return total

        lo, hi = -10**10 - 1, 10**10 + 1
        while lo < hi:
            mid = (lo + hi) // 2
            if count_le(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        return lo

