function bisectRight(arr, x) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (arr[mid] <= x) lo = mid + 1; else hi = mid;
    }
    return lo;
}
function bisectLeft(arr, x) {
    let lo = 0, hi = arr.length;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (arr[mid] < x) lo = mid + 1; else hi = mid;
    }
    return lo;
}

var kthSmallestProduct = function(nums1, nums2, k) {
    const n2 = nums2.length;
    function countLe(mid) {
        let total = 0;
        for (const a of nums1) {
            if (a === 0) {
                if (mid >= 0) total += n2;
            } else if (a > 0) {
                const thr = Math.floor(mid / a);
                total += bisectRight(nums2, thr);
            } else {
                const q = -a;
                const bMin = -Math.floor(mid / q);
                total += n2 - bisectLeft(nums2, bMin);
            }
        }
        return total;
    }
    let lo = -10000000001, hi = 10000000001;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (countLe(mid) >= k) hi = mid; else lo = mid + 1;
    }
    return lo;
};
